final:
module sync_up_counter(
    input clk,
    input rst,
    output reg [2:0] count
);

    always @(posedge clk) begin
        if (rst)
            count <= 3'b000;
        else
            count <= count + 1;
    end

  always @(*) begin
    if (1'b0) begin
      if (rst) begin
        count <= 3'b111;
      end
    end
  end

endmodule
